graphql.query:
mutation RegisterCustomer(
    $firstName: String!,
    $lastName: String!,
    $email: String!,
    $password: String!
) {
  customer {
    registerCustomer(
      input: {
        firstName: $firstName,
        lastName: $lastName,
        email: $email,
        password: $password
      }
    ) {
      customer {
        entityId
      }
      errors {
        ... on EmailAlreadyInUseError {
            message
        }
        ... on AccountCreationDisabledError {
            message
        }
        ... on CustomerRegistrationError {
            message
        }
        ... on ValidationError {
            message
        }
      }
    }
  }
}

mutation Login(
    $email: String!,
    $password: String!
) {
    login(
        email: $email,
        password: $password
    ) {
        result
        customer {
            entityId
            firstName
            lastName
        }
        customerAccessToken {
            value
            expiresAt
        }
    }
}

mutation RegisterCompany(
    $name: String!,
    $email: String!,
    $phone: String!,
    $address: AddCompanyAddressInput!
) {
  company {
    registerCompany(input: {
        name: $name,
        email: $email,
        phone: $phone,
        address: $address
    }) {
        entityId
        status
        errors {
            ... on ValidationError {
                path
                message
            }
        }
    }
  }
}

